}

std::string digest_hex(const std::string &text) {
    std::uint64_t h = digest_update(kDigestSeed, text);
    std::ostringstream os;
    os << std::hex << std::nouppercase << std::setfill('0') << std::setw(16) << h;
    return os.str();
}

