        entry.carry_weight = pick_int64(block, "carry_weight");
        entry.carry_drift = pick_int64(block, "carry_drift");
        if (!entry.name.empty()) {
            state.units[entry.name] = entry;
        }
    }
    state.valid = true;
    return state;
}

